 1→import { useMutation, useQueryClient } from '@tanstack/react-query';
 2→import { useTranslation } from 'react-i18next';
 3→
 4→import { saasConfigApi } from '@airlock-cloud/management-ui/api/apis';
 5→import { ServerErrorResponse } from '@airlock-cloud/management-ui/api/serverError';
 6→import useSetNotification from '@airlock-cloud/management-ui/common/use-set-notification/useSetNotification';
 7→import { ConfigActivation } from '@airlock-cloud/management-ui/domain/configActivation';
 8→
 9→function useActivateSaasConfig() {
10→	const { t } = useTranslation();
11→	const queryClient = useQueryClient();
12→	const setNotification = useSetNotification();
13→
14→	const { mutateAsync } = useMutation<ConfigActivation, ServerErrorResponse, string, unknown>({
15→		mutationFn: (tenantId: string) => saasConfigApi.activateSaasConfig(tenantId),
16→		onSuccess: async (configActivation: ConfigActivation, tenantId: string) => {
17→			await queryClient.invalidateQueries({
18→				queryKey: ['tenants', tenantId, 'config-activations'],
19→				refetchType: 'all',
20→			});
21→			if (configActivation) {
22→				setNotification({
23→					level: 'info',
24→					message: t(
25→						'features.tenants.configActivation.configActivationCard.configActivationSection.successfulSubmitNotification.description',
26→						{
27→							defaultValue: 'Activation in progress',
28→						}
29→					),
30→				});
31→			}
32→		},
33→	});
34→
35→	return mutateAsync;
36→}
37→
38→export default useActivateSaasConfig;
