 29→function OperationActionGroup() {
 30→	const { t } = useTranslation();
 31→	const tenantId = useRequiredTenantId();
 32→	const setNotification = useSetNotification();
 33→
 34→	const [isCreateTestUserModalOpen, setCreateTestUserModalOpen] = useState(false);
 35→
 36→	const { data: deployment } = usePolledTenantDeployment(tenantId);
 37→	const polledMostRecentActivation = usePolledMostRecentConfigActivation(tenantId);
 38→
 39→	const adminappUrl = `${import.meta.env.VITE_BASE_PATH}${new PublicPathBuilder().tenantIAMRedirect().build({ tenantId })}`;
 40→	// RejectedInvalidConfig and RejectedUnsupportedVersion should not occur
 41→	// when configurations are created via the Getting Started guide
 42→	const hasMostRecentActivationFailed =
 43→		polledMostRecentActivation?.status === ConfigActivationStatus.Failed ||
 44→		polledMostRecentActivation?.status === ConfigActivationStatus.RejectedInvalidConfig ||
 45→		polledMostRecentActivation?.status === ConfigActivationStatus.RejectedUnsupportedVersion;
 46→	const isActivating = !!polledMostRecentActivation && isConfigActivationOngoing(polledMostRecentActivation);
 47→
 48→	const isCreateTestUserDisabled =
 49→		!isDeploymentAvailable(deployment) || hasAdminappMtlsEnabled(deployment) || !FEATURE_FLAG_CREATE_USER_IN_TENANT;
 50→
 51→	const previousActivationRef = useRef<ConfigActivation | null>(null);
 52→	useEffect(() => {
 53→		const previousActivation = previousActivationRef.current;
 54→		const wasActivating = !!previousActivation && isConfigActivationOngoing(previousActivation);
 55→
 56→		if (wasActivating && !isActivating && polledMostRecentActivation?.status === ConfigActivationStatus.Success) {
 57→			setNotification({
 58→				level: 'success',
 59→				message: t('features.configuration.wizard.operation.deployment.result.success', {
 60→					defaultValue: 'Activation was successful',
 61→				}),
 62→			});
 63→		}
 64→		if (wasActivating && hasMostRecentActivationFailed) {
 65→			setNotification({
 66→				level: 'error',
 67→				message: t('features.configuration.wizard.operation.deployment.result.failure', {
 68→					defaultValue: 'Activation failed',
 69→				}),
 70→			});
 71→		}
 72→
 73→		previousActivationRef.current = polledMostRecentActivation;
 74→	}, [polledMostRecentActivation?.status]);
 75→
 76→	const errorPanelMessage = hasDeployment(deployment)
 77→		? t('features.configuration.wizard.operation.deployment.failure.panel.withDeployment.description', {
 78→				defaultValue:
 79→					"We couldn't activate your tenant. It is still running with the most recent valid configuration.",
 80→			})
 81→		: t('features.configuration.wizard.operation.deployment.failure.panel.withoutDeployment.description', {
 82→				defaultValue: "We couldn't activate your tenant.",
 83→			});
 84→
 85→	const createCreateTestUserTooltipLabel = (): string | undefined => {
 86→		if (!FEATURE_FLAG_CREATE_USER_IN_TENANT) {
 87→			return t(
 88→				'features.configuration.wizard.operation.userManagement.createTestUser.button.tooltipLabel.featureIsMissing',
 89→				{
 90→					defaultValue: 'This feature is currently not available.',
 91→				}
 92→			);
 93→		}
 94→		if (hasAdminappMtlsEnabled(deployment)) {
 95→			return t(
 96→				'features.configuration.wizard.operation.userManagement.createTestUser.button.tooltipLabel.adminappMtlsConfigured',
 97→				{
 98→					defaultValue: 'Test users cannot be created if mTLS is configured for Adminapp',
 99→				}
100→			);
101→		}
102→		if (!isDeploymentAvailable(deployment)) {
103→			return t(
104→				'features.configuration.wizard.operation.userManagement.createTestUser.button.tooltipLabel.deploymentIsNotAvailable',
105→				{
106→					defaultValue: 'A test user can only be created once the deployment has become available.',
107→				}
108→			);
109→		}
110→		return undefined;
111→	};
112→
113→	return (
114→		<>
115→			<div className="mt-2 flex flex-col gap-2">
116→				{hasMostRecentActivationFailed ? (
117→					<EmbeddedPanel
118→						title={t('features.configuration.wizard.operation.deployment.failure.panel.title', {
119→							defaultValue: 'Failed activation',
120→						})}
121→						message={errorPanelMessage}
122→						level="error"
123→					/>
124→				) : null}
125→				<ActionGroup>
126→					<DeploymentActionGroupItem tenantId={tenantId} />
127→					<ActionGroup.Item
128→						icon={{ icon: LoginIcon, color: 'black' }}
129→						title={t('features.configuration.wizard.operation.loginForm.title', {
130→							defaultValue: 'Login form',
131→						})}
132→						subtitle={t('features.configuration.wizard.operation.loginForm.subtitle', {
133→							defaultValue: 'Open the login form to test logging in',
134→						})}
135→						link={
136→							hasLoginUrl(deployment)
137→								? {
138→										href: deployment.loginUrl,
139→										label: t('features.configuration.wizard.operation.loginForm.link.label', {
140→											defaultValue: 'Open login form',
141→										}),
142→									}
143→								: undefined
144→						}
145→						disabled={!canLoginappBeOpened(deployment)}
146→					/>
147→					<ActionGroup.Item
148→						icon={{ icon: GroupIcon, color: 'black' }}
149→						title={t('features.configuration.wizard.operation.userManagement.title', {
150→							defaultValue: 'User management',
151→						})}
152→						subtitle={t('features.configuration.wizard.operation.userManagement.subtitle', {
153→							defaultValue: 'Create and manage users',
154→						})}
155→						secondaryButton={{
156→							label: t(
157→								'features.configuration.wizard.operation.userManagement.createTestUser.button.label',
158→								{
159→									defaultValue: 'Create test user',
160→								}
161→							),
162→							tooltipLabel: createCreateTestUserTooltipLabel(),
163→							action: () => setCreateTestUserModalOpen(true),
164→							disabled: isCreateTestUserDisabled,
165→						}}
166→						link={{
167→							href: adminappUrl,
168→							label: t('features.configuration.wizard.operation.userManagement.link.label', {
169→								defaultValue: 'Manage users',
170→							}),
171→						}}
172→						disabled={!isDeploymentAvailable(deployment)}
173→					/>
174→				</ActionGroup>
175→			</div>
176→			<CreateTestUserModal isOpen={isCreateTestUserModalOpen} close={() => setCreateTestUserModalOpen(false)} />
177→		</>
178→	);
179→}
180→
181→export default OperationActionGroup;
