  1→import PendingIcon from '@airlock/material-symbols/svg/outlined/pending.svg';
  2→import PlayCircleIcon from '@airlock/material-symbols/svg/outlined/play_circle.svg';
  3→import RocketIcon from '@airlock/material-symbols/svg/outlined/rocket.svg';
  4→import RocketLaunchIcon from '@airlock/material-symbols/svg/outlined/rocket_launch.svg';
  5→import React, { useEffect } from 'react';
  6→import { useTranslation } from 'react-i18next';
  7→
  8→import { useTranslatableMessageJSONStringTranslations } from '@airlock-cloud/management-ui/common/error.utils';
  9→import { asTranslatableMessageJSONString } from '@airlock-cloud/management-ui/common/translatableMessage';
 10→import useAdminHasPermission from '@airlock-cloud/management-ui/common/use-admin-has-permission/useAdminHasPermission';
 11→import usePolledMostRecentConfigActivation from '@airlock-cloud/management-ui/common/use-config-activation/usePolledMostRecentConfigActivation';
 12→import usePolledTenantDeployment from '@airlock-cloud/management-ui/common/use-polled-tenant-deployment/usePolledTenantDeployment';
 13→import useSetErrorNotificationFromServerResponse from '@airlock-cloud/management-ui/common/use-set-notification/useSetErrorNotificationFromServerResponse';
 14→import useSetNotification from '@airlock-cloud/management-ui/common/use-set-notification/useSetNotification';
 15→import { ActionGroup } from '@airlock-cloud/management-ui/components/action-group';
 16→import { ActionGroupItemIconColor } from '@airlock-cloud/management-ui/components/action-group/ActionGroup';
 17→import {
 18→	ConfigActivationStatus,
 19→	isConfigActivationOngoing,
 20→} from '@airlock-cloud/management-ui/domain/configActivation';
 21→import { isDeploymentAvailable } from '@airlock-cloud/management-ui/domain/tenantDeployment';
 22→import useActivateSaasConfig from '@airlock-cloud/management-ui/features/config-wizard/use-activate-saas-config/useActivateSaasConfig';
 23→
 24→function DeploymentActionGroupItem({ tenantId }: DeploymentActionGroupItemProps) {
 25→	const { t } = useTranslation();
 26→	const { data: deployment } = usePolledTenantDeployment(tenantId);
 27→	const polledMostRecentActivation = usePolledMostRecentConfigActivation(tenantId);
 28→	const activateSaasConfig = useActivateSaasConfig();
 29→	const hasConfigActivatePermission = useAdminHasPermission('config.activate');
 30→	const submittedAtRef = React.useRef<number | null>(null);
 31→	const setNotification = useSetNotification();
 32→	const setErrorNotificationFromServerResponse = useSetErrorNotificationFromServerResponse();
 33→	const translateMessageJSONString = useTranslatableMessageJSONStringTranslations();
 34→	/**
 35→	 * `isActivating` requires the ConfigActivation to reload, which may take a brief moment, such that it may
 36→	 * seem to a user that the action was not submitted. To make sure the feedback appears immediately, we also
 37→	 * use `wasSubmitted` to keep track if the action was triggered and optimistically update the action button immediately.
 38→	 */
 39→	const [isSubmitting, setIsSubmitting] = React.useState(false);
 40→	const isActivating =
 41→		isSubmitting || (!!polledMostRecentActivation && isConfigActivationOngoing(polledMostRecentActivation));
 42→
 43→	/**
 44→	 * Make sure to reset the submitting state again so that the components are updated according to
 45→	 * the status of the config activation and deployment.
 46→	 */
 47→	useEffect(() => {
 48→		if (isSubmitting && polledMostRecentActivation?.activationDate) {
 49→			const activationTime = polledMostRecentActivation.activationDate.getTime();
 50→			if (submittedAtRef.current === null || activationTime > submittedAtRef.current) {
 51→				setIsSubmitting(false);
 52→			}
 53→		}
 54→	}, [polledMostRecentActivation?.activationDate]);
 55→
 56→	/**
 57→	 * Order matters! We want to display the activating state as soon as the activation is submitted
 58→	 * (and not only once the ConfigActivation update is retrieved) and thus check for this condition first.
 59→	 */
 60→	function getActivationState(): ActivationState {
 61→		if (isActivating) {
 62→			return DEPLOYMENT_STATES.Pending;
 63→		}
 64→		if (polledMostRecentActivation === null) {
 65→			return DEPLOYMENT_STATES.Inactive;
 66→		}
 67→		if (isDeploymentAvailable(deployment)) {
 68→			return DEPLOYMENT_STATES.Active;
 69→		}
 70→		// RejectedInvalidConfig and RejectedUnsupportedVersion should not occur
 71→		// when configurations are created via the Getting Started guide
 72→		if (
 73→			polledMostRecentActivation.status === ConfigActivationStatus.Failed ||
 74→			polledMostRecentActivation.status === ConfigActivationStatus.RejectedInvalidConfig ||
 75→			polledMostRecentActivation.status === ConfigActivationStatus.RejectedUnsupportedVersion
 76→		) {
 77→			return DEPLOYMENT_STATES.Inactive;
 78→		}
 79→		return DEPLOYMENT_STATES.Unavailable;
 80→	}
 81→
 82→	function getActivationIcon(): {
 83→		icon: string | number;
 84→		color?: ActionGroupItemIconColor;
 85→	} {
 86→		switch (getActivationState()) {
 87→			case DEPLOYMENT_STATES.Active:
 88→				return { icon: RocketLaunchIcon, color: 'green' };
 89→			case DEPLOYMENT_STATES.Inactive:
 90→				return { icon: RocketIcon };
 91→			case DEPLOYMENT_STATES.Pending:
 92→				return { icon: PendingIcon, color: 'blue' };
 93→			case DEPLOYMENT_STATES.Unavailable:
 94→				return { icon: PendingIcon, color: 'yellow' };
 95→		}
 96→	}
 97→
 98→	function getActivationTitle() {
 99→		switch (getActivationState()) {
100→			case DEPLOYMENT_STATES.Active:
101→				return t('features.configuration.wizard.operation.deployment.title.success', {
102→					defaultValue: 'Active',
103→				});
104→			case DEPLOYMENT_STATES.Inactive:
105→				return t('features.configuration.wizard.operation.deployment.title.inactive', {
106→					defaultValue: 'Inactive',
107→				});
108→			case DEPLOYMENT_STATES.Pending:
109→				return t('features.configuration.wizard.operation.deployment.title.pending', {
110→					defaultValue: 'Activation in progress..',
111→				});
112→			case DEPLOYMENT_STATES.Unavailable:
113→				return t('features.configuration.wizard.operation.deployment.title.unavailable', {
114→					defaultValue: 'Tenant unavailable',
115→				});
116→		}
117→	}
118→
119→	function getActivationSubtitle() {
120→		switch (getActivationState()) {
121→			case DEPLOYMENT_STATES.Active:
122→				return t('features.configuration.wizard.operation.deployment.subtitle.success', {
123→					defaultValue: 'Your tenant is ready',
124→				});
125→			case DEPLOYMENT_STATES.Inactive:
126→				return t('features.configuration.wizard.operation.deployment.subtitle.inactive', {
127→					defaultValue: 'Activate tenant to enable login and user management',
128→				});
129→			case DEPLOYMENT_STATES.Pending:
130→				return t('features.configuration.wizard.operation.deployment.subtitle.pending', {
131→					defaultValue: 'This may take a few minutes',
132→				});
133→			case DEPLOYMENT_STATES.Unavailable:
134→				return t('features.configuration.wizard.operation.deployment.subtitle.unavailable', {
135→					defaultValue: 'Tenant cannot currently be reached',
136→				});
137→		}
138→	}
139→
140→	const handleSubmit = async () => {
141→		submittedAtRef.current = Date.now();
142→		setIsSubmitting(true);
143→		await activateSaasConfig(tenantId, {
144→			onError: (error) => {
145→				setIsSubmitting(false);
146→				// TODO ALSAAS-4330: this is a code duplicate from src/form/Form.tsx
147→				// TODO ALSAAS-4330: this should be moved into one of the error notification handlers.
148→				if (error.status && error.status !== 400) {
149→					setErrorNotificationFromServerResponse(error);
150→				} else if (error.error) {
151→					const translatableMessage = asTranslatableMessageJSONString(
152→						error.error.code,
153→						error.error.meta?.parameters
154→					);
155→					setNotification({
156→						level: 'error',
157→						message: translateMessageJSONString(translatableMessage),
158→					});
159→				}
160→			},
161→		});
162→	};
163→
164→	return (
165→		<ActionGroup.Item
166→			icon={getActivationIcon()}
167→			title={getActivationTitle()}
168→			subtitle={getActivationSubtitle()}
169→			actionButton={{
170→				label: t('features.configuration.wizard.operation.deployment.button.label', {
171→					defaultValue: 'Activate tenant',
172→				}),
173→				icon: PlayCircleIcon,
174→				action: handleSubmit,
175→				loading: isActivating,
176→			}}
177→			// TODO ALSAAS-4138: Use appropriate permission here
178→			disabled={!hasConfigActivatePermission}
179→		/>
180→	);
181→}
182→
183→type DeploymentActionGroupItemProps = {
184→	tenantId: string;
185→};
186→
187→const DEPLOYMENT_STATES = {
188→	Inactive: 'inactive',
189→	Pending: 'pending',
190→	Active: 'active',
191→	Unavailable: 'unavailable',
192→} as const;
193→
194→type ActivationState = (typeof DEPLOYMENT_STATES)[keyof typeof DEPLOYMENT_STATES];
195→
196→export default DeploymentActionGroupItem;
