 1→import {
 2→	ConfigActivationAttributesDto,
 3→	ConfigActivationCreateAttributesDto,
 4→	ConfigActivationCreateDto,
 5→	ConfigActivationDto,
 6→	ConfigActivationStatusDto as ConfigActivationStatus,
 7→} from '@airlock-cloud/management-api';
 8→import { Config } from '@airlock-cloud/management-ui/domain/config';
 9→
10→type ConfigActivation = Omit<ConfigActivationDto, 'type' | 'attributes'> &
11→	Omit<ConfigActivationAttributesDto, 'config' | 'activationDate' | 'statusUpdatedDate'> & {
12→		config: Omit<Config, 'id'>;
13→		activationDate: Date;
14→		statusUpdatedDate?: Date;
15→		updatedAt?: Date;
16→	};
17→
18→type ConfigActivationCreate = Omit<ConfigActivationCreateDto, 'type' | 'attributes'> &
19→	ConfigActivationCreateAttributesDto;
20→
21→function isConfigActivationOngoing(configActivation: ConfigActivation): boolean {
22→	return (
23→		configActivation.status === ConfigActivationStatus.Pending ||
24→		configActivation.status === ConfigActivationStatus.Progressing
25→	);
26→}
27→
28→export type { ConfigActivation, ConfigActivationCreate };
29→export { ConfigActivationStatus, isConfigActivationOngoing };
