 1→import { SaasConfigAttributesDto, SaasConfigDto } from '@airlock-cloud/management-api';
 2→
 3→type SaasConfigAttributes = Omit<SaasConfigAttributesDto, 'uploadDate'> & {
 4→	uploadDate: Date;
 5→};
 6→
 7→type SaasConfig = Omit<SaasConfigDto, 'type' | 'attributes'> & SaasConfigAttributes;
 8→
 9→export type { SaasConfigAttributes, SaasConfig };
10→
